// Cross-sell: extract guest data from Beds24 booking webhook payload
const booking = items[0].json;
return [{
  json: {
    bookingId:  booking.bookId   || booking.id || '',
    guestName:  booking.guestFirstName + ' ' + (booking.guestName || ''),
    guestEmail: booking.guestEmail || '',
    checkIn:    booking.firstNight || booking.arrival || '',
    numAdults:  booking.numAdult || 2,
    trigger:    'booking'
  }
}];

// Build cross-sell email with pre-filled restaurant URL
const b = items[0].json;
const restUrl = `https://porta-dirta.hobbitonranch.com/restaurante?fecha=${b.checkIn}&personas=${b.numAdults}&nombre=${encodeURIComponent(b.guestName)}&email=${encodeURIComponent(b.guestEmail)}`;
const expUrl  = 'https://events.hobbitonranch.com';

const body = `Estimado/a ${b.guestName},\n\n`
  + `Estamos encantados de que hayas elegido Porta D'irta para tu estancia.\n\n`
  + `Para hacer tu visita aún más especial, te invitamos a:\n\n`
  + `🍽️  RESERVAR UNA MESA EN NUESTRO RESTAURANTE\n`
  + `Tu mesa para ${b.numAdults} personas está a un clic de distancia:\n`
  + `${restUrl}\n\n`
  + `🌿  DESCUBRIR NUESTRAS EXPERIENCIAS LOCALES\n`
  + `Sierra de Irta, Kayak, Cata de Vinos y más:\n`
  + `${expUrl}\n\n`
  + `Nuestro equipo está disponible para organizar todo por ti.\n\n`
  + `Hasta pronto,\nEl equipo de Porta D'irta\n+34 644 026 066`;

return [{ json: {
  toEmail:  b.guestEmail,
  subject:  `Tu estancia en Porta D'irta — todo listo para ti`,
  body,
  bookingId: b.bookingId
} }];

// Load pricing rules and compute recommendations
const occupancyData = items[0].json;
const rules = {
  rooms: {
    'habitacion-mediterranea': { base: 120, floor: 90,  ceiling: 200 },
    'suite-junior':            { base: 180, floor: 140, ceiling: 300 },
    'suite-panoramica':        { base: 250, floor: 200, ceiling: 420 }
  },
  tiers: [
    { occupancyMin: 0,  occupancyMax: 50, multiplier: 1.00 },
    { occupancyMin: 51, occupancyMax: 70, multiplier: 1.10 },
    { occupancyMin: 71, occupancyMax: 85, multiplier: 1.25 },
    { occupancyMin: 86, occupancyMax: 100,multiplier: 1.40 }
  ],
  specialDates: [
    { date: '2026-08-15', multiplier: 1.50 },
    { date: '2026-08-14', multiplier: 1.40 },
    { date: '2026-06-24', multiplier: 1.30 },
    { date: '2026-07-25', multiplier: 1.30 }
  ]
};

const days = occupancyData.days || [];
const adjustments = [];

for (const day of days) {
  const occ = day.occupancyPercent || 0;
  const tier = rules.tiers.find(t => occ >= t.occupancyMin && occ <= t.occupancyMax) || rules.tiers[0];
  const special = rules.specialDates.find(s => s.date === day.date);
  const multiplier = special ? Math.max(special.multiplier, tier.multiplier) : tier.multiplier;

  for (const [roomSlug, roomRules] of Object.entries(rules.rooms)) {
    const recommended = Math.round((roomRules.base * multiplier) / 5) * 5;
    const safePrice = Math.max(roomRules.floor, Math.min(roomRules.ceiling, recommended));
    const currentPrice = day.prices?.[roomSlug] || roomRules.base;

    if (Math.abs(safePrice - currentPrice) >= 10) {
      adjustments.push({
        date: day.date,
        roomSlug,
        currentPrice,
        recommendedPrice: safePrice,
        occupancy: occ,
        reason: `${occ}% ocupación — ${tier.occupancyMax <= 50 ? 'baja demanda' : tier.occupancyMax <= 70 ? 'normal' : tier.occupancyMax <= 85 ? 'alta demanda' : 'pico máximo'}${ special ? ' + festivo' : ''}`
      });
    }
  }
}

return [{ json: {
  adjustments,
  hasAdjustments: adjustments.length > 0,
  analysisDate: new Date().toISOString()
} }];

