// Parse Gemini summary and store pending yield action
const geminiRaw = items[0].json;
const adjustments = $('Compute Price Recommendations').first().json.adjustments;

let summary = `${adjustments.length} ajustes de precio recomendados para los próximos 30 días.`;
try {
  const text = geminiRaw.content?.[0]?.text || '{}';
  const parsed = JSON.parse(text);
  if (parsed.summary) summary = parsed.summary;
} catch(e) {}

const actionKey = 'yield_' + Date.now().toString(36);
const staticData = $getWorkflowStaticData('global');
if (!staticData.pendingYield) staticData.pendingYield = {};
staticData.pendingYield[actionKey] = { adjustments, ts: Date.now() };

return [{ json: { summary, actionKey, count: adjustments.length } }];

// Handle yield approval/dismiss callback
const update = items[0].json;
const callbackData = update.callback_query?.data || '';
const chatId = update.callback_query?.message?.chat?.id?.toString();

if (!callbackData.startsWith('yield')) return [];

const parts = callbackData.split('_');
const cbAction = parts[0]; // yieldapply | yielddismiss
const actionKey = parts.slice(1).join('_');

const staticData = $getWorkflowStaticData('global');
const pending = staticData.pendingYield?.[actionKey];
if (!pending) return [{ json: { error: 'Yield action expired', chatId } }];

delete staticData.pendingYield[actionKey];

if (cbAction === 'yielddismiss') {
  return [{ json: { dismissed: true, chatId, count: pending.adjustments.length } }];
}

return [{ json: { apply: true, chatId, adjustments: pending.adjustments } }];

// Apply price adjustments to Beds24 sequentially with delay to respect rate limit
const { adjustments, chatId } = items[0].json;
const results = [];

for (const adj of adjustments) {
  try {
    const resp = await fetch(
      `https://beds24.com/api/v2/inventory/prices`,
      {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${$env.BEDS24_API_TOKEN}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          propertyId: $env.BEDS24_PROP_ID,
          roomId: adj.roomSlug,
          date: adj.date,
          price: adj.recommendedPrice
        })
      }
    );
    results.push({ date: adj.date, room: adj.roomSlug, price: adj.recommendedPrice, ok: resp.ok });
    // Respect Beds24 1-request-at-a-time rate limit
    await new Promise(r => setTimeout(r, 700));
  } catch(e) {
    results.push({ date: adj.date, room: adj.roomSlug, error: e.message });
  }
}

const successCount = results.filter(r => r.ok).length;
return [{ json: { results, successCount, total: adjustments.length, chatId } }];
